import React, {createContext, useCallback, useContext, useEffect, useMemo, useRef, useState} from 'react';
import type {ColorMode, IKitsTheme, IKitsThemeContextValues, KitsThemeOverride} from '@lmb-it/kitsconcerto-types';
import {defaultTheme, deepMerge, resolveTokenValue} from '@lmb-it/kitsconcerto-types';
import {generateCssVariables} from './resolvers.web';
import {PRIME_OVERRIDES_CSS} from './primeOverrides.web';

const KitsThemeContext = createContext<IKitsThemeContextValues | null>(null);

export interface KitsThemeProviderProps {
    theme?: KitsThemeOverride;
    children: React.ReactNode;
}

export function KitsThemeProvider({theme: themeOverride, children}: KitsThemeProviderProps) {
    const mergedTheme = useMemo(
        () => (themeOverride ? deepMerge(defaultTheme, themeOverride as Record<string, any>) as IKitsTheme : defaultTheme),
        [themeOverride],
    );

    const [colorMode, setColorMode] = useState<ColorMode>(mergedTheme.config.initialColorMode);
    const manualOverrideRef = useRef(false);

    const toggleColorMode = useCallback(() => {
        manualOverrideRef.current = true;
        setColorMode(m => (m === 'light' ? 'dark' : 'light'));
    }, []);

    const setColorModeManual = useCallback((mode: ColorMode) => {
        manualOverrideRef.current = true;
        setColorMode(mode);
    }, []);

    // Inject CSS custom properties into :root + body overrides
    useEffect(() => {
        const cssVars = generateCssVariables(mergedTheme, colorMode);
        let styleEl = document.getElementById('kits-theme-vars') as HTMLStyleElement | null;
        if (!styleEl) {
            styleEl = document.createElement('style');
            styleEl.id = 'kits-theme-vars';
            document.head.appendChild(styleEl);
        }
        styleEl.textContent = `:root {\n${cssVars}\n}`;

        // Toggle dark class & data-theme on <html> for Tailwind dark: variants & CSS selectors
        document.documentElement.classList.toggle('dark', colorMode === 'dark');
        document.documentElement.setAttribute('data-theme', colorMode);
    }, [mergedTheme, colorMode]);

    // Inject PrimeReact dark-mode-compatible overrides (once)
    useEffect(() => {
        if (document.getElementById('kits-prime-overrides')) return;
        const styleEl = document.createElement('style');
        styleEl.id = 'kits-prime-overrides';
        styleEl.textContent = PRIME_OVERRIDES_CSS;
        document.head.appendChild(styleEl);
    }, []);

    // System color mode detection
    useEffect(() => {
        if (!mergedTheme.config.useSystemColorMode) return;
        const mq = window.matchMedia('(prefers-color-scheme: dark)');

        // Only apply system preference if user hasn't manually toggled
        if (!manualOverrideRef.current) {
            setColorMode(mq.matches ? 'dark' : 'light');
        }

        const handler = (e: MediaQueryListEvent) => {
            // System change resets manual override — user expects system to take over again
            if (!manualOverrideRef.current) {
                setColorMode(e.matches ? 'dark' : 'light');
            }
        };
        mq.addEventListener('change', handler);
        return () => mq.removeEventListener('change', handler);
    }, [mergedTheme.config.useSystemColorMode]);

    const resolveToken = useCallback(
        (token: string) => resolveTokenValue(mergedTheme, colorMode, token, 'web'),
        [mergedTheme, colorMode],
    );

    const value = useMemo<IKitsThemeContextValues>(
        () => ({theme: mergedTheme, colorMode, toggleColorMode, setColorMode: setColorModeManual, resolveToken}),
        [mergedTheme, colorMode, toggleColorMode, setColorModeManual, resolveToken],
    );

    return (
        <KitsThemeContext.Provider value={value}>
            {children}
        </KitsThemeContext.Provider>
    );
}

export function useKitsTheme(): IKitsThemeContextValues {
    const ctx = useContext(KitsThemeContext);
    if (!ctx) {
        // Fallback: return default theme values if used outside provider
        return {
            theme: defaultTheme,
            colorMode: 'light',
            toggleColorMode: () => {},
            setColorMode: () => {},
            resolveToken: (token: string) => resolveTokenValue(defaultTheme, 'light', token, 'web'),
        };
    }
    return ctx;
}

export {KitsThemeContext};
